              <button
                onClick={handleDownloadWord}
                className="w-full flex items-center justify-between p-4 bg-blue-50 border border-blue-100 rounded-lg hover:bg-blue-100 transition-colors group"
              >
                <div className="text-left">
                  <span className="block font-bold text-blue-900 text-lg">Download Word (DOC)</span>
                  <span className="block text-sm text-blue-700">Editable document</span>
                </div>
                <FileText size={24} className="text-blue-600 group-hover:scale-110 transition-transform" />
              </button>
            </div>

            <button
              onClick={() => setIsDownloadOptionsOpen(false)}
              className="mt-6 w-full py-3 text-slate-500 font-bold hover:bg-slate-100 rounded-lg transition-colors"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <InvoiceControls 
        onSaveToHistory={handleSaveToHistory}
        onDownload={() => setIsDownloadOptionsOpen(true)}
        hasEmail={!!data.billToEmail}
      />

      <div className="container mx-auto max-w-5xl flex justify-between px-4 pt-4 md:px-8 print:hidden">
        {/* Actions Left */}
        <div className="flex items-center gap-2">
           <button
             onClick={handleSaveToHistory}
             className="flex items-center gap-2 text-slate-700 font-bold bg-white hover:bg-slate-50 px-4 py-2 rounded-lg shadow-sm border border-slate-200 hover:border-blue-300 transition-all"
             title="Save current invoice to history"
           >
             <Save size={18} />
             Save
           </button>
           <button
              onClick={handleNewInvoice}
              className="flex items-center gap-2 text-white font-bold bg-blue-900 hover:bg-blue-800 px-4 py-2 rounded-lg shadow-md border border-blue-900 transition-all hover:shadow-lg"
              title="Create a new blank invoice with next ID"
          >
              <FilePlus size={18} />
              New Invoice
          </button>
        </div>

        <button
          onClick={() => setIsHistoryModalOpen(true)}
          className="flex items-center gap-2 text-slate-600 hover:text-blue-900 font-bold bg-white px-4 py-2 rounded-lg shadow-sm border border-slate-200 hover:border-blue-300 transition-all"
        >
          <History size={18} />
          View History / Paid Status
        </button>
      </div>

      <main className="container mx-auto max-w-5xl p-4 md:p-8 lg:p-12 print:p-0 print:max-w-none">

        {/* Paper Container (White Box) - Added ID for html2pdf */}
        <div id="invoice-container" className="bg-white shadow-2xl rounded-xl p-8 md:p-12 print:shadow-none print:p-0 print:rounded-none">

          <ProviderHeader />

          {/* Invoice Info & Bill To Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">

            {/* Bill To Section */}
            <div className="border-2 border-blue-500 rounded-lg p-5 relative print:border-none print:p-0">
              <div className="flex justify-between items-start mb-4">
                 <h2 className="text-xs font-extrabold text-indigo-600 uppercase tracking-widest mt-1">Bill To</h2>

                 {/* Client DB Controls (Hidden in Print) */}
                 <div className="flex items-center gap-2 no-print">

                   {/* Dropdown for selecting saved customers */}
                   <div className="relative group">
                     <select 
                       onChange={handleLoadCustomer}
                       value=""
                       className="appearance-none bg-blue-50 text-blue-900 text-xs font-bold py-1.5 px-3 pr-8 rounded-md border border-blue-200 hover:border-blue-400 focus:outline-none cursor-pointer shadow-sm"
                       title="Load a saved customer"
                     >
                       <option value="" disabled>Select Saved Client</option>
                       {savedCustomers.length > 0 ? (
                          savedCustomers.map(c => (
                            <option key={c.id} value={c.id}>{c.name}</option>
                          ))
                       ) : (
                          <option value="" disabled>No saved clients</option>
                       )}
                     </select>
                     <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-blue-900">
                       <Users size={12} />
                     </div>
                   </div>

                   <button
                     onClick={handleSaveCustomer}
                     title={matchingCustomer ? "Update existing client" : "Save new client"}
                     className="bg-emerald-50 text-emerald-700 hover:bg-emerald-100 p-1.5 rounded-md border border-emerald-200 transition-colors shadow-sm"
                   >
                     <Save size={16} />
                   </button>

                   <button
                     onClick={() => setIsCustomerManagerOpen(true)}
                     title="Manage saved clients"
                     className="bg-slate-50 text-slate-600 hover:bg-slate-100 p-1.5 rounded-md border border-slate-200 transition-colors shadow-sm"
                   >
                     <Settings size={16} />
                   </button>
                 </div>
              </div>

              <div className="space-y-3">
                <input
                  type="text"
                  placeholder="Company / Agency Name"
                  className="w-full font-bold text-2xl text-slate-900 border-b-2 border-dashed border-slate-300 focus:border-blue-700 focus:outline-none placeholder-slate-300 py-1 print:border-none print:p-0"
                  value={data.billToName}
                  onChange={(e) => updateField('billToName', e.target.value)}
                />
                <textarea
                  placeholder="Address&#10;City, State Zip"
                  className="w-full text-lg font-medium text-slate-700 resize-none border-b-2 border-dashed border-slate-300 focus:border-blue-700 focus:outline-none placeholder-slate-300 py-1 print:border-none print:p-0 leading-tight"
                  rows={2}
                  value={data.billToAddress}
                  onChange={(e) => updateField('billToAddress', e.target.value)}
                />

                {/* Contact Details */}
                <div className="space-y-2 mt-2">
                   <div className="flex items-center gap-2 text-base text-slate-600">
                    <span className="print:hidden text-indigo-400 w-5"><MapPin size={18} /></span>
                    <input
                      type="text"
                      placeholder="Phone Number (Optional)"
                      className="w-full border-b border-dashed border-slate-300 focus:border-blue-700 focus:outline-none placeholder-slate-300 py-0.5 print:border-none print:p-0"
                      value={data.billToPhone}
                      onChange={(e) => updateField('billToPhone', e.target.value)}
                    />
                  </div>
                  <div className="flex items-center gap-2 text-base text-slate-600">
                    <span className="print:hidden text-indigo-400 w-5"><Mail size={18} /></span>
                    <input
                      type="email"
                      placeholder="Email Address (Required)"
                      className="w-full border-b border-dashed border-slate-300 focus:border-blue-700 focus:outline-none placeholder-slate-300 py-0.5 print:border-none print:p-0"
                      value={data.billToEmail}
                      onChange={(e) => updateField('billToEmail', e.target.value)}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Invoice Meta Data */}
            <div className="flex flex-col md:items-end">
              <h2 className="text-5xl font-black text-blue-900 uppercase tracking-tighter mb-6 print:text-blue-900">Invoice</h2>

              <div className="w-full md:w-2/3 space-y-3">
                <div className="flex justify-between items-center border-b border-slate-100 pb-1">
                  <label className="text-base font-bold text-slate-500">Invoice #</label>
                  <div className="flex items-center">
                    <span className="text-slate-400 mr-1 text-lg print:hidden">#</span>
                    <input
                      type="text"
                      className="text-right bg-transparent w-40 font-mono font-bold text-xl text-slate-800 focus:outline-none focus:bg-slate-50 rounded px-2"
                      value={data.invoiceNumber}
                      onChange={(e) => updateField('invoiceNumber', e.target.value)}
                    />
                  </div>
                </div>

                <div className="flex justify-between items-center border-b border-slate-100 pb-1">
                  <label className="text-base font-bold text-slate-500">Date</label>
                  <input
                    type="date"
                    className="text-right font-bold text-xl text-slate-800 bg-transparent w-48 focus:outline-none focus:bg-slate-50 rounded px-2"
                    value={data.date}
                    onChange={(e) => updateField('date', e.target.value)}
                  />
                </div>

                <div className="flex justify-between items-center border-b border-slate-100 pb-1">
                  <label className="text-base font-bold text-slate-500">Due Date</label>
                  <input
                    type="date"
                    className="text-right font-bold text-xl text-rose-600 bg-transparent w-48 focus:outline-none focus:bg-slate-50 rounded px-2"
                    value={data.dueDate}
                    onChange={(e) => updateField('dueDate', e.target.value)}
                  />
                </div>
              </div>
            </div>
          </div>

          {/* Services Table */}
          <div className="mb-8">
            <div className="rounded-t-lg border-2 border-blue-900 overflow-hidden">
              <table className="w-full text-left border-collapse table-fixed">
                <thead>
                  <tr className="bg-blue-900 text-white print:bg-blue-900 print:text-white">
                    <th className="py-2 px-1 text-xs font-bold uppercase tracking-wider w-[20%] border-r border-blue-800">Date</th>
                    <th className="py-2 px-1 text-xs font-bold uppercase tracking-wider w-[19%] border-r border-blue-800">Patient</th>
                    <th className="py-2 px-1 text-xs font-bold uppercase tracking-wider w-[27%] border-r border-blue-800">Service / Description</th>
                    <th className="py-2 px-1 text-xs font-bold uppercase tracking-wider w-[7%] text-center border-r border-blue-800">Miles</th>
                    <th className="py-2 px-1 text-xs font-bold uppercase tracking-wider w-[6%] text-center border-r border-blue-800">Qty</th>
                    <th className="py-2 px-1 text-xs font-bold uppercase tracking-wider w-[10%] text-right border-r border-blue-800">Rate</th>
                    <th className="py-2 px-2 text-xs font-bold uppercase tracking-wider w-[11%] text-right">Amount</th>
                    <th className="py-2 px-0 w-[0%] no-print bg-blue-900"></th>
                  </tr>
                </thead>
                <tbody className="align-middle text-slate-700">
                  {data.items.map((item, index) => (
                    <tr key={item.id} className={`border-b border-slate-200 group hover:bg-blue-50 print:hover:bg-transparent print-break-inside-avoid ${index % 2 === 0 ? 'bg-white' : 'bg-slate-50 print:bg-white'}`}>
                      {/* Date */}
                      <td className="p-0.5 align-middle border-r border-slate-100">
                        <input
                          type="date"
                          className="w-full bg-transparent text-[11px] font-medium focus:outline-none text-slate-700 h-6 px-1"
                          value={item.date}
                          onChange={(e) => updateItem(item.id, 'date', e.target.value)}
                        />
                      </td>

                      {/* Patient */}
                      <td className="p-0.5 align-middle border-r border-slate-100">
                         <div className="relative">
                           <textarea
                            placeholder="Patient Name"
                            rows={1}
                            className="w-full bg-transparent text-[11px] font-bold focus:outline-none placeholder:text-slate-300 placeholder:font-normal px-1 resize-none overflow-hidden"
                            value={item.patientName}
                            onChange={(e) => updateItem(item.id, 'patientName', e.target.value)}
                            style={{ height: '24px' }}
                          />
                         </div>
                      </td>

                      {/* Service & Desc */}
                      <td className="p-0.5 align-middle border-r border-slate-100">
                        <div className="flex flex-col">
                          <select
                            className="w-full bg-transparent font-bold text-slate-800 text-[11px] focus:outline-none appearance-none cursor-pointer print:appearance-none h-6 px-1 truncate"
                            value={item.serviceName}
                            onChange={(e) => updateItem(item.id, 'serviceName', e.target.value)}
                          >
                            {SERVICE_OPTIONS.map(opt => (
                              <option key={opt.id} value={opt.name}>{opt.name}</option>
                            ))}
                          </select>
                          <textarea
                            placeholder="Details..."
                            rows={1}
                            className="w-full bg-transparent text-[10px] text-slate-500 focus:outline-none placeholder:text-slate-300 italic px-1 resize-none overflow-hidden"
                            value={item.description}
                            onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                            style={{ height: '16px' }}
                          />
                        </div>
                      </td>

                      {/* Miles */}
                      <td className="p-0.5 align-middle border-r border-slate-100">
                         <input
                            type="number"
                            min="0"
                            className="w-full text-center bg-transparent text-[11px] font-medium text-slate-700 focus:outline-none h-6"
                            value={item.miles}
                            onChange={(e) => updateItem(item.id, 'miles', parseFloat(e.target.value) || 0)}
                          />
                      </td>

                      {/* Quantity */}
                      <td className="p-0.5 align-middle border-r border-slate-100">
                        <input
                            type="number"
                            min="0"
                            className="w-full text-center bg-transparent text-[11px] font-medium text-slate-700 focus:outline-none h-6"
                            value={item.quantity}
                            onChange={(e) => updateItem(item.id, 'quantity', parseFloat(e.target.value) || 0)}
                          />
                      </td>

                      {/* Rate */}
                      <td className="p-0.5 align-middle text-right border-r border-slate-100">
                          <input
                            type="number"
                            min="0"
                            step="0.01"
                            className="w-full text-right bg-transparent text-[11px] font-medium text-slate-700 focus:outline-none h-6 px-1"
                            value={item.rate}
                            onChange={(e) => updateItem(item.id, 'rate', parseFloat(e.target.value) || 0)}
                          />
                      </td>

                      {/* Amount (Calculated) */}
                      <td className="p-0.5 align-middle text-right font-bold text-[11px] text-blue-900 px-2">
                        ${(item.quantity * item.rate).toFixed(2)}
                      </td>

                      {/* Delete */}
                      <td className="p-0.5 align-middle text-center no-print">
                        <button
                          onClick={() => removeItem(item.id)}
                          className="text-slate-300 hover:text-rose-500 transition-colors"
                          title="Remove Row"
                        >
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="flex items-center gap-4 mt-4 no-print">
              <button
                type="button"
                onClick={addItem}
                className="flex items-center gap-2 text-base font-bold text-blue-800 hover:text-blue-950 transition-colors bg-blue-50 px-4 py-2 rounded-lg hover:bg-blue-100"
              >
                <Plus size={18} />
                Add Service Line
              </button>

              <div className="h-6 w-px bg-slate-300"></div>

              <button
                type="button"
                onClick={() => setIsMagicModalOpen(true)}
                className="flex items-center gap-2 text-base font-bold text-indigo-600 hover:text-indigo-800 transition-colors group bg-indigo-50 px-4 py-2 rounded-lg hover:bg-indigo-100"
                title="Paste rough notes and let AI build the invoice"
              >
                <Sparkles size={18} className="group-hover:animate-pulse" />
                Magic Add
              </button>
            </div>
          </div>

          {/* Footer Grid: Notes & Totals */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12 print:gap-8 page-break-inside-avoid">

            {/* Notes & Terms */}
            <div className="space-y-6">
              <div>
                <div className="flex items-center justify-between mb-2">
                  <h3 className="text-xs font-extrabold text-slate-400 uppercase tracking-widest">Notes</h3>
                  <button 
                    type="button"
                    onClick={handlePolishNotes}
                    disabled={isPolishingNotes || !data.notes}
                    className="flex items-center gap-2 text-xs font-bold text-blue-800 hover:text-blue-950 bg-blue-100 px-2 py-1 rounded-full transition-colors no-print disabled:opacity-50"
                    title="Make professional with AI"
                  >
                     {isPolishingNotes ? <Loader2 size={12} className="animate-spin" /> : <Wand2 size={12} />}
                     AI Polish
                  </button>
                </div>
                <textarea
                  className="w-full text-base bg-slate-50 border-2 border-slate-100 rounded-lg p-3 focus:border-blue-700 focus:outline-none resize-none print:bg-transparent print:border-none print:p-0"
                  rows={3}
                  placeholder="Additional notes..."
                  value={data.notes}
                  onChange={(e) => updateField('notes', e.target.value)}
                />
              </div>

              {/* Payment Terms Container */}
              <div className="bg-slate-50 border-2 border-slate-100 rounded-lg p-4 print:bg-transparent print:border-none print:p-0 flex flex-col gap-2">
                 <textarea
                  className="w-full text-xl font-bold text-blue-900 bg-transparent border-none p-0 focus:outline-none resize-none print:bg-transparent"
                  rows={2}
                  value={data.paymentTerms}
                  onChange={(e) => updateField('paymentTerms', e.target.value)}
                />
                 {/* Dynamic Payment Due Date - Footer */}
                 <div className="text-base font-medium text-rose-600 print:text-rose-600">
                    Payment due by {formattedDueDate}
                 </div>
              </div>
            </div>

            {/* Calculations Summary */}
            <div className="flex flex-col gap-3">
              <div className="flex justify-between items-center py-2 border-b border-slate-200">
                <span className="text-lg text-slate-600 font-medium">Service Subtotal</span>
                <span className="font-bold text-xl text-slate-800">${subtotal.toFixed(2)}</span>
              </div>

              <div className="flex justify-between items-center py-2 border-b border-slate-200">
                <div className="flex items-center gap-2">
                   <span className="text-lg text-slate-600 font-medium">Mileage</span>
                   <div className="flex items-center text-sm bg-slate-100 rounded px-2 py-0.5 print:bg-transparent border border-slate-200 print:border-none">
                      <span className="text-slate-400 mr-1 font-bold">@</span>
                      <span className="mr-1 text-slate-600 font-bold">{totalMiles} mi x $</span>
                      <input 
                        type="number"
                        className="w-12 bg-transparent text-slate-800 font-bold focus:outline-none"
                        value={data.mileageRate}
                        step="0.01"
                        onChange={(e) => updateField('mileageRate', parseFloat(e.target.value) || 0)}
                      />
                   </div>
                </div>
                <span className="font-bold text-xl text-slate-800">${mileageTotal.toFixed(2)}</span>
              </div>

              <div className="flex justify-between items-end py-4 mt-2 border-t-4 border-slate-800 bg-slate-50 px-6 rounded-lg print:bg-transparent print:px-0">
                <span className="text-2xl font-black text-slate-800 uppercase tracking-wide">Total</span>
                <span className="text-5xl font-black text-rose-600 leading-none">${grandTotal.toFixed(2)}</span>
              </div>
            </div>
          </div>
        </div>

      </main>
    </div>
  );
};

export default App;
